package Batch71;

public class Caluculations {
public
	static  void  main(String[] args) {
		// TODO Auto-generated method stub
		int a=10,b=5;
	    int c=a+b;
	    int d=a-b;
	    int r=a*b;
	    int g=a/b;
	    int h=a%b;
	    System.out.println("addition="+c);
	    System.out.println("subtraction="+d);
	    System.out.println("multiplication="+r);
	    System.out.println("devision="+g);
	    System.out.println("reminder="+h);

	}

}
